import{_ as a,o as t,c as l,ag as i}from"./chunks/framework.DEqXEGcv.js";const c=JSON.parse('{"title":"File Management","description":"","frontmatter":{},"headers":[],"relativePath":"en/docs/guide/files.md","filePath":"en/docs/guide/files.md"}'),r={name:"en/docs/guide/files.md"};function o(n,e,s,d,p,h){return t(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="file-management" tabindex="-1">File Management <a class="header-anchor" href="#file-management" aria-label="Permalink to &quot;File Management&quot;">​</a></h1><p>RDE includes a full-featured file manager that delivers a desktop-grade file experience in the browser.</p><h2 id="basic-operations" tabindex="-1">Basic Operations <a class="header-anchor" href="#basic-operations" aria-label="Permalink to &quot;Basic Operations&quot;">​</a></h2><ul><li><strong>Browse</strong>: Tree directory navigation with breadcrumb path bar</li><li><strong>Create</strong>: Create files and folders</li><li><strong>Copy/Cut/Paste</strong>: Supports keyboard shortcuts</li><li><strong>Rename</strong>: Double-click filename or press F2</li><li><strong>Delete</strong>: Supports recycle bin and permanent delete</li><li><strong>Search</strong>: Search by filename</li></ul><h2 id="file-upload" tabindex="-1">File Upload <a class="header-anchor" href="#file-upload" aria-label="Permalink to &quot;File Upload&quot;">​</a></h2><p>Multiple upload methods supported:</p><ul><li><strong>Drag &amp; drop</strong>: Drag files into the file manager window</li><li><strong>Click to upload</strong>: Use the upload button to select files</li><li><strong>Folder upload</strong>: Upload entire folders</li></ul><h3 id="large-file-resumable-upload" tabindex="-1">Large File Resumable Upload <a class="header-anchor" href="#large-file-resumable-upload" aria-label="Permalink to &quot;Large File Resumable Upload&quot;">​</a></h3><p>Resumable uploads based on TUS protocol, supporting 10 GB+ files:</p><ul><li>Automatic recovery on network interruption</li><li>Real-time upload progress display</li><li>Support for pause/resume</li></ul><h2 id="file-download" tabindex="-1">File Download <a class="header-anchor" href="#file-download" aria-label="Permalink to &quot;File Download&quot;">​</a></h2><ul><li>Single file direct download</li><li>Multi-file/folder packaged as ZIP download</li></ul><h2 id="file-preview" tabindex="-1">File Preview <a class="header-anchor" href="#file-preview" aria-label="Permalink to &quot;File Preview&quot;">​</a></h2><p>Built-in file previewers for multiple formats:</p><table tabindex="0"><thead><tr><th>Type</th><th>Supported Formats</th></tr></thead><tbody><tr><td>Images</td><td>JPG, PNG, GIF, SVG, WebP</td></tr><tr><td>Video</td><td>MP4, WebM, MKV</td></tr><tr><td>Audio</td><td>MP3, FLAC, WAV, OGG</td></tr><tr><td>Documents</td><td>TXT, Markdown, PDF</td></tr><tr><td>Code</td><td>Syntax-highlighted code viewer</td></tr></tbody></table><h2 id="file-sharing" tabindex="-1">File Sharing <a class="header-anchor" href="#file-sharing" aria-label="Permalink to &quot;File Sharing&quot;">​</a></h2><p>Generate share links to easily share files with others:</p><ul><li>Set share password (optional)</li><li>Set expiration time</li><li>Limit download count</li></ul><h2 id="samba-sharing" tabindex="-1">Samba Sharing <a class="header-anchor" href="#samba-sharing" aria-label="Permalink to &quot;Samba Sharing&quot;">​</a></h2><p>One-click LAN file sharing via SMB protocol, allowing other devices to access files on RDE.</p>',20)])])}const f=a(r,[["render",o]]);export{c as __pageData,f as default};
